const props = $input.item.json.properties;
const customerId = String(parseInt(props.id_google_account?.number || 0));
const campaignId = String(parseInt(props.id_google_camp?.number || 0));
const campaignName = props['Nome Campanha']?.formula?.string
  || props['Name']?.title?.[0]?.plain_text
  || 'Campanha';

const today = new Date();
const fmt = (d) => d.toISOString().split('T')[0];
const yesterday = new Date(today); yesterday.setDate(today.getDate() - 1);
const start7  = new Date(today); start7.setDate(today.getDate() - 7);
const start30 = new Date(today); start30.setDate(today.getDate() - 30);
const startMes = new Date(today.getFullYear(), today.getMonth(), 1);

return [{ json: {
  customer_id:   customerId,
  campaign_id:   campaignId,
  campaign_name: campaignName,
  periodo_7d:  { start: fmt(start7),   end: fmt(yesterday) },
  periodo_30d: { start: fmt(start30),  end: fmt(yesterday) },
  periodo_mes: { start: fmt(startMes), end: fmt(yesterday) },
  hoje: fmt(today)
}}];

